+#[derive(Debug, serde::Serialize)]
+struct RobotAgentInventorySummary {
+    installed: usize,
+    running: usize,
+    configured: usize,
+    installed_but_idle: usize,
+}
+
+#[derive(Debug, serde::Serialize)]
